      // Copy IR flags from the original binop to the new ones.
      if (auto *NewBO = dyn_cast<BinaryOperator>(True)) {
        NewBO->copyIRFlags(&I);
        if (auto *FalseBO = dyn_cast<BinaryOperator>(False))
          FalseBO->copyIRFlags(&I);
      }
      // If True and False are equivalent (considering commutativity),
      // return the common value directly.
      if (True == False)
        return True;
      if (Instruction::isCommutative(Opcode)) {
        auto *TrueBO = dyn_cast<BinaryOperator>(True);
        auto *FalseBO = dyn_cast<BinaryOperator>(False);
        if (TrueBO && FalseBO &&
            TrueBO->getOperand(0) == FalseBO->getOperand(1) &&
            TrueBO->getOperand(1) == FalseBO->getOperand(0))
          return True;
      }
    }
